const checkpoints = [];
const machines = JSON.parse(localStorage.getItem('machine_models') || '[]');
const cart = JSON.parse(localStorage.getItem('cart') || 'null');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
// Find eligible 3-axis mills under $60k with table >= 800x400 mm in cnc_milling_machines
const eligible = machines.filter(m => {
  if (!m) return false;
  if (m.productCategory !== 'cnc_milling_machines') return false;
  if (m.machineType !== '3_axis') return false;
  if (typeof m.axisCount === 'number' && m.axisCount !== 3) return false;
  if (typeof m.price !== 'number' || m.price > 60000) return false;
  if (typeof m.tableSizeXmm !== 'number' || m.tableSizeXmm < 800) return false;
  if (typeof m.tableSizeYmm !== 'number' || m.tableSizeYmm < 400) return false;
  return true;
});
eligible.sort((a, b) => (b.spindlePowerKw || 0) - (a.spindlePowerKw || 0));
const target = eligible[0] || null;
let targetCartItem = null;
if (cart && target) {
  targetCartItem = cartItems.find(ci => ci.cartId === cart.id && ci.itemType === 'machine_model' && ci.productId === target.id) || null;
}
// CP1 (0.4): Correct most-powerful qualifying machine is in the cart
checkpoints.push({ passed: !!targetCartItem, weight: 0.4 });
// CP2 (0.6): That cart line has quantity exactly 1
checkpoints.push({ passed: !!targetCartItem && targetCartItem.quantity === 1, weight: 0.6 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const categories = JSON.parse(localStorage.getItem('configurable_machine_categories') || '[]');
const groups = JSON.parse(localStorage.getItem('config_option_groups') || '[]');
const options = JSON.parse(localStorage.getItem('config_options') || '[]');
const configs = JSON.parse(localStorage.getItem('machine_configurations') || '[]');
const quotes = JSON.parse(localStorage.getItem('quote_requests') || '[]');
// Identify the entry-level CNC milling machine category dynamically by name
const entryCat = categories.find(c => (c.name || '').toLowerCase().includes('entry-level cnc milling machine')) || null;
if (!entryCat) {
  checkpoints.push({ passed: false, weight: 1.0 });
  return 0;
}
const spindleGroupIds = groups.filter(g => g.categoryId === entryCat.id && g.code === 'spindle').map(g => g.id);
const toolGroupIds = groups.filter(g => g.categoryId === entryCat.id && g.code === 'tool_changer').map(g => g.id);
const coolantGroupIds = groups.filter(g => g.categoryId === entryCat.id && g.code === 'coolant').map(g => g.id);
// Analyze each quote + configuration for this category
const analyzed = quotes.map(q => {
  const cfg = configs.find(c => c.id === q.configurationId);
  if (!cfg || cfg.categoryId !== entryCat.id) return null;
  const selectedOpts = options.filter(o => Array.isArray(cfg.selectedOptionIds) && cfg.selectedOptionIds.includes(o.id));
  const spindlePower = selectedOpts
    .filter(o => spindleGroupIds.includes(o.groupId) && typeof o.powerKw === 'number')
    .reduce((max, o) => Math.max(max, o.powerKw), 0);
  const includesAtc = selectedOpts.some(o => toolGroupIds.includes(o.groupId) && o.includesAtc === true);
  const hasCoolant = selectedOpts.some(o => coolantGroupIds.includes(o.groupId) && o.coolantType && o.coolantType !== 'none');
  const totalPrice = typeof cfg.totalPrice === 'number' ? cfg.totalPrice : 0;
  return { quote: q, cfg, spindlePower, includesAtc, hasCoolant, totalPrice };
}).filter(x => x !== null);
// CP1 (0.4): At least one entry-level configuration with spindle power ≥ 7.5 kW has a quote
const withSpindle = analyzed.filter(x => x.spindlePower >= 7.5);
checkpoints.push({ passed: withSpindle.length > 0, weight: 0.4 });
// CP2 (0.4): At least one configuration also has ATC, some coolant, and total price ≤ 45,000
const fullyQualifying = withSpindle.filter(x => x.includesAtc && x.hasCoolant && x.totalPrice <= 45000);
checkpoints.push({ passed: fullyQualifying.length > 0, weight: 0.4 });
// CP3 (0.2): For a fully-qualifying configuration, quote has non-empty name and plausible email
const hasContact = fullyQualifying.some(x => {
  const name = (x.quote.name || '').trim();
  const email = (x.quote.email || '').trim();
  return !!name && email.includes('@');
});
checkpoints.push({ passed: hasContact, weight: 0.2 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const parts = JSON.parse(localStorage.getItem('spare_parts') || '[]');
const machines = JSON.parse(localStorage.getItem('machine_models') || '[]');
const cart = JSON.parse(localStorage.getItem('cart') || 'null');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
// Find ProMill 500 machine model by name
const promill = machines.find(m => (m.name || '').toLowerCase() === 'promill 500');
if (!promill || !cart) {
  checkpoints.push({ passed: false, weight: 1.0 });
  return 0;
}
// Eligible main spindle parts for ProMill 500, model year 2022, in stock
const eligible = parts.filter(p => {
  if (!p) return false;
  if (p.machineModelId !== promill.id) return false;
  if (p.partCategory !== 'main_spindle') return false;
  if (p.availabilityStatus !== 'in_stock') return false;
  if (!Array.isArray(p.compatibleModelYears) || !p.compatibleModelYears.includes(2022)) return false;
  if (p.isMainSpindle !== true) return false;
  return true;
});
eligible.sort((a, b) => (a.price || 0) - (b.price || 0));
const target = eligible[0] || null;
let targetCartItem = null;
if (target) {
  targetCartItem = cartItems.find(ci => ci.cartId === cart.id && ci.itemType === 'spare_part' && ci.productId === target.id) || null;
}
// CP1 (0.4): Cheapest qualifying main spindle is present in cart
checkpoints.push({ passed: !!targetCartItem && targetCartItem.quantity >= 1, weight: 0.4 });
// CP2 (0.3): Quantity is at least 2
checkpoints.push({ passed: !!targetCartItem && targetCartItem.quantity >= 2, weight: 0.3 });
// CP3 (0.3): Quantity is exactly 2
checkpoints.push({ passed: !!targetCartItem && targetCartItem.quantity === 2, weight: 0.3 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const courses = JSON.parse(localStorage.getItem('training_courses') || '[]');
const regs = JSON.parse(localStorage.getItem('training_registrations') || '[]');
const cutoff = new Date('2024-09-01T00:00:00Z').getTime();
// Find earliest qualifying online course (beginner or introductory) starting on/after cutoff
const candidates = courses.filter(c => {
  if (!c) return false;
  if (c.deliveryMethod !== 'online') return false;
  if (c.level !== 'beginner' && c.level !== 'introductory') return false;
  const start = new Date(c.startDate).getTime();
  return !isNaN(start) && start >= cutoff;
});
candidates.sort((a, b) => new Date(a.startDate).getTime() - new Date(b.startDate).getTime());
const targetCourse = candidates[0] || null;
if (!targetCourse) {
  checkpoints.push({ passed: false, weight: 1.0 });
  return 0;
}
const regsForTarget = regs.filter(r => r && r.courseId === targetCourse.id);
// Take any registration for this course
const reg = regsForTarget[regsForTarget.length - 1] || null;
// CP1 (0.5): There is a registration for the earliest qualifying course
checkpoints.push({ passed: !!reg, weight: 0.5 });
// CP2 (0.3): Participants count is exactly 1
checkpoints.push({ passed: !!reg && reg.participantsCount === 1, weight: 0.3 });
// CP3 (0.2): Registration has non-empty name and plausible email
const hasContact = !!reg && (reg.fullName || '').trim() && (reg.email || '').trim().includes('@');
checkpoints.push({ passed: hasContact, weight: 0.2 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const dealers = JSON.parse(localStorage.getItem('dealers') || '[]');
const dealerMessages = JSON.parse(localStorage.getItem('dealer_messages') || '[]');
const geocodes = JSON.parse(localStorage.getItem('postal_geocodes') || '[]');
// Determine user location for postal code 60601 (match BusinessLogic strategy)
let userLocation = null;
const geo = geocodes.find(g => g.postalCode === '60601');
if (geo && typeof geo.latitude === 'number' && typeof geo.longitude === 'number') {
  userLocation = { latitude: geo.latitude, longitude: geo.longitude };
} else {
  const matches = dealers.filter(d => d.postalCode === '60601' && typeof d.latitude === 'number' && typeof d.longitude === 'number');
  if (matches.length > 0) {
    const avgLat = matches.reduce((sum, d) => sum + d.latitude, 0) / matches.length;
    const avgLon = matches.reduce((sum, d) => sum + d.longitude, 0) / matches.length;
    userLocation = { latitude: avgLat, longitude: avgLon };
  }
}
if (!userLocation) {
  checkpoints.push({ passed: false, weight: 1.0 });
  return 0;
}
// Compute distances to authorized service centers
const toRad = deg => (deg * Math.PI) / 180;
const haversine = (aLat, aLon, bLat, bLon) => {
  const R = 6371; // km
  const dLat = toRad(bLat - aLat);
  const dLon = toRad(bLon - aLon);
  const rLat1 = toRad(aLat);
  const rLat2 = toRad(bLat);
  const aa = Math.sin(dLat / 2) ** 2 + Math.sin(dLon / 2) ** 2 * Math.cos(rLat1) * Math.cos(rLat2);
  const c = 2 * Math.atan2(Math.sqrt(aa), Math.sqrt(1 - aa));
  return R * c;
};
const authorized = dealers.filter(d => d && d.isAuthorizedServiceCenter === true);
const withDistances = authorized.map(d => {
  if (typeof d.latitude !== 'number' || typeof d.longitude !== 'number') {
    return { dealer: d, distanceKm: null };
  }
  return {
    dealer: d,
    distanceKm: haversine(userLocation.latitude, userLocation.longitude, d.latitude, d.longitude)
  };
}).filter(dd => dd.distanceKm !== null && dd.distanceKm <= 100);
withDistances.sort((a, b) => a.distanceKm - b.distanceKm);
const nearest = withDistances[0] ? withDistances[0].dealer : null;
let msgToNearest = null;
if (nearest) {
  msgToNearest = dealerMessages.find(m => m && m.dealerId === nearest.id) || null;
}
// CP1 (0.7): A message was sent to the nearest authorized service dealer within 100 km of 60601
checkpoints.push({ passed: !!nearest && !!msgToNearest, weight: 0.7 });
// CP2 (0.3): That message has non-empty name, email, and message body
const hasContent = !!msgToNearest && (msgToNearest.name || '').trim() && (msgToNearest.email || '').trim().includes('@') && (msgToNearest.message || '').trim();
checkpoints.push({ passed: hasContent, weight: 0.3 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const manualDownloaded = JSON.parse(localStorage.getItem('task6_userManualDownloaded') || 'false');
const safetyDownloaded = JSON.parse(localStorage.getItem('task6_safetyInstructionsDownloaded') || 'false');
// CP1 (0.5): User manual download event recorded
checkpoints.push({ passed: !!manualDownloaded, weight: 0.5 });
// CP2 (0.5): Safety instructions download event recorded
checkpoints.push({ passed: !!safetyDownloaded, weight: 0.5 });
return check   points.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const caseStudies = JSON.parse(localStorage.getItem('case_studies') || '[]');
const favorites = JSON.parse(localStorage.getItem('favorite_case_studies') || '[]');
// Find aerospace industry id dynamically
const industries = JSON.parse(localStorage.getItem('industries') || '[]');
const aero = industries.find(i => (i.name || '').toLowerCase().includes('aerospace')) || { id: 'aerospace' };
// Newest aerospace case study with machineType=5_axis_machining_center and material=titanium
const candidates = caseStudies.filter(cs => {
  if (!cs) return false;
  if (cs.industryId !== aero.id) return false;
  if (cs.machineType !== '5_axis_machining_center') return false;
  if (cs.material !== 'titanium') return false;
  return true;
});
candidates.sort((a, b) => new Date(b.datePublished).getTime() - new Date(a.datePublished).getTime());
const target = candidates[0] || null;
let favorited = false;
if (target) {
  favorited = favorites.some(f => f && f.caseStudyId === target.id);
}
const copiedId = localStorage.getItem('task7_linkCopiedCaseStudyId') || '';
// CP1 (0.5): Target case study is in favorites
checkpoints.push({ passed: !!target && favorited, weight: 0.5 });
// CP2 (0.5): Link was copied for that same target case study
checkpoints.push({ passed: !!target && copiedId === target.id, weight: 0.5 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const plans = JSON.parse(localStorage.getItem('maintenance_plans') || '[]');
const subs = JSON.parse(localStorage.getItem('maintenance_subscriptions') || '[]');
// Find cheapest active plan with annual on-site inspection and monthly price ≤ 200
const qualifyingPlans = plans.filter(p => {
  if (!p) return false;
  if (p.status !== 'active') return false;
  if (p.includesAnnualOnSiteInspection !== true) return false;
  if (typeof p.monthlyPrice !== 'number' || p.monthlyPrice > 200) return false;
  return true;
});
qualifyingPlans.sort((a, b) => (a.monthlyPrice || 0) - (b.monthlyPrice || 0));
const target = qualifyingPlans[0] || null;
if (!target) {
  checkpoints.push({ passed: false, weight: 1.0 });
  return 0;
}
const subsForTarget = subs.filter(s => s && s.planId === target.id);
// CP1 (0.6): At least one subscription request for the cheapest qualifying plan
checkpoints.push({ passed: subsForTarget.length > 0, weight: 0.6 });
// From those, check for early October 2024 preferred start date (1st–10th)
const earlyOctSubs = subsForTarget.filter(s => {
  if (!s.preferredStartDate) return false;
  const d = new Date(s.preferredStartDate);
  if (isNaN(d.getTime())) return false;
  const year = d.getUTCFullYear();
  const month = d.getUTCMonth(); // 0-based, so October = 9
  const day = d.getUTCDate();
  return year === 2024 && month === 9 && day >= 1 && day <= 10;
});
// CP2 (0.25): A subscription for this plan specifies an early October 2024 start date
checkpoints.push({ passed: earlyOctSubs.length > 0, weight: 0.25 });
// CP3 (0.15): That subscription has non-empty name and plausible email
const hasContact = earlyOctSubs.some(s => {
  const name = (s.name || '').trim();
  const email = (s.email || '').trim();
  return !!name && email.includes('@');
});
checkpoints.push({ passed: hasContact, weight: 0.15 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
